-- SecurityOS PostgreSQL schema starter
CREATE TABLE security_identities (id TEXT PRIMARY KEY, tenant_id TEXT NOT NULL, email TEXT NOT NULL, display_name TEXT NOT NULL, identity_type TEXT NOT NULL, status TEXT NOT NULL, mfa_enabled BOOLEAN NOT NULL DEFAULT FALSE, last_login_at TIMESTAMPTZ, risk_score NUMERIC NOT NULL DEFAULT 0, groups JSONB NOT NULL DEFAULT '[]', metadata JSONB NOT NULL DEFAULT '{}', created_by TEXT NOT NULL, created_at TIMESTAMPTZ NOT NULL, updated_at TIMESTAMPTZ NOT NULL, UNIQUE (tenant_id, email));
CREATE TABLE security_roles (id TEXT PRIMARY KEY, tenant_id TEXT NOT NULL, name TEXT NOT NULL, description TEXT, permissions JSONB NOT NULL DEFAULT '[]', system BOOLEAN NOT NULL DEFAULT FALSE, status TEXT NOT NULL, created_by TEXT NOT NULL, created_at TIMESTAMPTZ NOT NULL, updated_at TIMESTAMPTZ NOT NULL, UNIQUE (tenant_id, name));
CREATE TABLE security_groups (id TEXT PRIMARY KEY, tenant_id TEXT NOT NULL, name TEXT NOT NULL, description TEXT, members JSONB NOT NULL DEFAULT '[]', role_ids JSONB NOT NULL DEFAULT '[]', status TEXT NOT NULL, created_by TEXT NOT NULL, created_at TIMESTAMPTZ NOT NULL, updated_at TIMESTAMPTZ NOT NULL, UNIQUE (tenant_id, name));
CREATE TABLE security_role_assignments (id TEXT PRIMARY KEY, tenant_id TEXT NOT NULL, subject_type TEXT NOT NULL, subject_id TEXT NOT NULL, role_id TEXT NOT NULL, scope TEXT, expires_at TIMESTAMPTZ, status TEXT NOT NULL, assigned_by TEXT NOT NULL, revoked_at TIMESTAMPTZ, created_at TIMESTAMPTZ NOT NULL, updated_at TIMESTAMPTZ NOT NULL);
CREATE TABLE security_policies (id TEXT PRIMARY KEY, tenant_id TEXT NOT NULL, name TEXT NOT NULL, description TEXT, effect TEXT NOT NULL, subject_roles JSONB NOT NULL DEFAULT '[]', actions JSONB NOT NULL DEFAULT '[]', resources JSONB NOT NULL DEFAULT '[]', conditions JSONB NOT NULL DEFAULT '{}', priority INTEGER NOT NULL DEFAULT 0, status TEXT NOT NULL, created_by TEXT NOT NULL, created_at TIMESTAMPTZ NOT NULL, updated_at TIMESTAMPTZ NOT NULL);
CREATE TABLE security_sessions (id TEXT PRIMARY KEY, tenant_id TEXT NOT NULL, identity_id TEXT NOT NULL, status TEXT NOT NULL, ip_address TEXT, user_agent TEXT, expires_at TIMESTAMPTZ NOT NULL, revoked_at TIMESTAMPTZ, created_at TIMESTAMPTZ NOT NULL, updated_at TIMESTAMPTZ NOT NULL);
CREATE TABLE security_api_keys (id TEXT PRIMARY KEY, tenant_id TEXT NOT NULL, owner_id TEXT NOT NULL, name TEXT NOT NULL, key_prefix TEXT NOT NULL, key_hash TEXT NOT NULL, scopes JSONB NOT NULL DEFAULT '[]', status TEXT NOT NULL, expires_at TIMESTAMPTZ, last_used_at TIMESTAMPTZ, revoked_at TIMESTAMPTZ, created_by TEXT NOT NULL, created_at TIMESTAMPTZ NOT NULL, updated_at TIMESTAMPTZ NOT NULL);
CREATE TABLE security_secrets (id TEXT PRIMARY KEY, tenant_id TEXT NOT NULL, name TEXT NOT NULL, description TEXT, environment TEXT NOT NULL, encrypted_value TEXT NOT NULL, masked_value TEXT NOT NULL, version INTEGER NOT NULL DEFAULT 1, tags JSONB NOT NULL DEFAULT '[]', status TEXT NOT NULL, rotated_at TIMESTAMPTZ, created_by TEXT NOT NULL, created_at TIMESTAMPTZ NOT NULL, updated_at TIMESTAMPTZ NOT NULL, UNIQUE (tenant_id, environment, name));
CREATE TABLE security_secret_versions (id TEXT PRIMARY KEY, tenant_id TEXT NOT NULL, secret_id TEXT NOT NULL, version INTEGER NOT NULL, encrypted_value TEXT NOT NULL, masked_value TEXT NOT NULL, created_by TEXT NOT NULL, created_at TIMESTAMPTZ NOT NULL, updated_at TIMESTAMPTZ NOT NULL);
CREATE TABLE security_compliance_controls (id TEXT PRIMARY KEY, tenant_id TEXT NOT NULL, framework TEXT NOT NULL, code TEXT NOT NULL, title TEXT NOT NULL, description TEXT, owner_id TEXT, status TEXT NOT NULL, severity TEXT NOT NULL, due_date DATE, evidence_ids JSONB NOT NULL DEFAULT '[]', created_by TEXT NOT NULL, created_at TIMESTAMPTZ NOT NULL, updated_at TIMESTAMPTZ NOT NULL);
CREATE TABLE security_compliance_evidence (id TEXT PRIMARY KEY, tenant_id TEXT NOT NULL, control_id TEXT NOT NULL, title TEXT NOT NULL, evidence_type TEXT NOT NULL, uri TEXT, notes TEXT, uploaded_by TEXT NOT NULL, created_at TIMESTAMPTZ NOT NULL, updated_at TIMESTAMPTZ NOT NULL);
CREATE TABLE security_access_reviews (id TEXT PRIMARY KEY, tenant_id TEXT NOT NULL, name TEXT NOT NULL, reviewer_id TEXT NOT NULL, status TEXT NOT NULL, due_at TIMESTAMPTZ, completed_at TIMESTAMPTZ, items JSONB NOT NULL DEFAULT '[]', created_by TEXT NOT NULL, created_at TIMESTAMPTZ NOT NULL, updated_at TIMESTAMPTZ NOT NULL);
CREATE TABLE security_findings (id TEXT PRIMARY KEY, tenant_id TEXT NOT NULL, title TEXT NOT NULL, description TEXT, category TEXT NOT NULL, severity TEXT NOT NULL, status TEXT NOT NULL, owner_id TEXT, resolved_at TIMESTAMPTZ, created_by TEXT NOT NULL, created_at TIMESTAMPTZ NOT NULL, updated_at TIMESTAMPTZ NOT NULL);
CREATE TABLE security_events (id TEXT PRIMARY KEY, tenant_id TEXT NOT NULL, event TEXT NOT NULL, source TEXT NOT NULL, actor_id TEXT NOT NULL, data JSONB NOT NULL DEFAULT '{}', created_at TIMESTAMPTZ NOT NULL, updated_at TIMESTAMPTZ NOT NULL);
CREATE TABLE security_audit_logs (id TEXT PRIMARY KEY, tenant_id TEXT NOT NULL, actor_id TEXT NOT NULL, role TEXT NOT NULL, action TEXT NOT NULL, entity_type TEXT NOT NULL, entity_id TEXT, before JSONB, after JSONB, created_at TIMESTAMPTZ NOT NULL, updated_at TIMESTAMPTZ NOT NULL);
CREATE INDEX idx_security_identities_tenant ON security_identities (tenant_id);
CREATE INDEX idx_security_assignments_subject ON security_role_assignments (tenant_id, subject_type, subject_id);
CREATE INDEX idx_security_audit_tenant_created ON security_audit_logs (tenant_id, created_at DESC);
CREATE INDEX idx_security_events_tenant_created ON security_events (tenant_id, created_at DESC);
CREATE INDEX idx_security_findings_status ON security_findings (tenant_id, status, severity);
